class Solution:
    def distinctSequences(self, n: int) -> int:
        MOD = 10**9 + 7
        if n == 1:
            return 6

        # dp[a][b] = number of sequences ending with a and b
        dp = [[0] * 7 for _ in range(7)]

        # Initialize for sequences of length 2
        for a in range(1, 7):
            for b in range(1, 7):
                if a != b and math.gcd(a, b) == 1:
                    dp[a][b] = 1

        for length in range(3, n + 1):
            new_dp = [[0] * 7 for _ in range(7)]
            for a in range(1, 7):
                for b in range(1, 7):
                    if a == b:
                        continue
                    if math.gcd(a, b) != 1:
                        continue
                    for c in range(1, 7):
                        if b == c:
                            continue
                        if math.gcd(b, c) != 1:
                            continue
                        new_dp[b][c] = (new_dp[b][c] + dp[a][b]) % MOD
            dp = new_dp

        result = 0
        for a in range(1, 7):
            for b in range(1, 7):
                result = (result + dp[a][b]) % MOD
        return result

